sql:
SELECT reaction_name, stoichiometry, ec_number
FROM reactions
WHERE substrates LIKE '%C%' AND ec_number LIKE 'EC 2%';

external_knowledge:
- 'cholesterol' is a key term indicating the focus on cholesterol-related experiments;
- 'completed' refers to experiments that have reached their successful conclusion;
- 'currents of flux' metaphorically refers to the flux values in the reactions;
- 'climate conditions' symbolically represents the different types of conditions (environmental, genetic, etc.) that influence reactions in these experiments.

sql:
SELECT experiment_name 
FROM experiments
WHERE status = 'in_progress' AND created_by = 1;

SELECT reaction_id, reaction_name, stoichiometry, reaction_type, substrates, products, gene_association, ec_number
FROM reactions
WHERE reaction_id = 1;

